/* techniques q01 (122 mục) — engine-API đợt 95-100 Ch.97 - gop trung 2026-07-20 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]=window.__LIBQ["the-gioi-hoan-my"]["q01"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]["techniques"]={"updatedAt":"2026-07-04","count":122,"techniques":[{"id":"ren-luyen-than-the-duoi-may-som","name":"Rèn luyện thân thể dưới mây sớm","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Phàm","hePhai":"Thạch Thôn","soHuu":["Người đàn ông trung niên dạy lũ trẻ (chưa đặt tên)"],"blurb":"Phương pháp luyện thể tận dụng sinh khí mạnh nhất lúc mặt trời mới mọc dưới làn mây sớm.","detail":"Phương pháp rèn luyện thân thể của Thạch Thôn: lúc mặt trời mới mọc sinh khí mạnh nhất, rèn luyện dưới làn mây sớm giúp bồi đắp sinh cơ, cường gân tráng cốt, hoạt huyết luyện gân. Là thói quen của cả thôn từ trẻ nhỏ đến người già để sinh tồn trong mãng sơn.","nguon":["@c0001"]},{"id":"hit-tho-tinh-khi-dat-troi","name":"Hít thở tinh khí đất trời","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Phàm","hePhai":"Thạch Thôn","soHuu":[],"blurb":"Phương pháp người già khoanh chân ngồi trên tảng đá hít thở tinh khí đất trời buổi sáng.","detail":"Vào buổi sáng, người già trong thôn khoanh chân ngồi trên tảng đá lớn hít thở tinh khí đất trời để bồi dưỡng tinh khí thần.","nguon":["@c0001"]},{"id":"cot-van","name":"Cốt văn","loai":"khac","loaiLabel":"Sức mạnh ký tự thần bí","phamCap":"Chưa rõ","hePhai":"Chủng tộc Thái Cổ","soHuu":["Thạch Vân Phong","Chú nhóc (chưa đặt tên)"],"blurb":"Những ký tự thần bí hiển hóa bẩm sinh trên xương cốt của một chủng tộc mạnh mẽ thời Thái Cổ. (+) Truyền thụ trọng yếu của Bổ Thiên các, chỉ dành cho đệ tử có thiên phú nghịch thiên. [CAN-SOAT-GOP]","detail":"Cốt văn là những ký tự hiển hóa bẩm sinh trên xương cốt của một chủng tộc mạnh mẽ thời Thái Cổ, ẩn chứa sức mạnh thần bí khó dò. Khi vận dụng, một quầng sáng xuất hiện và ký tự nổi lên trên lòng bàn tay như đúc bằng kim loại, ban cho sức mạnh thể chất phi thường — nhóc tỳ hơn một tuổi nhờ cốt văn nhấc nổi khối đá xanh cao hơn người mình. Phải cá biệt hóa cốt văn vào trong cơ thể, mất mấy năm và đại đa số không thành công. Học thành tài sẽ mạnh hơn thế hệ cha chú nhiều lần. Thứ Thạch Vân Phong nghiên cứu hơn mười năm vẫn kém xa Thiên Cốt Văn truyền thuyết thời cổ đại.","nguon":["@c0002","@c0023","@c0038","@c0020","@c0015","@c0037","@c0065","@c0107"],"aliases":["Phù Văn","văn lạc","Phù văn nguyên thủy"]},{"id":"thien-cot-van","name":"Thiên Cốt Văn","loai":"khac","loaiLabel":"Cốt văn truyền thuyết","phamCap":"Chưa rõ","hePhai":"Truyền thuyết thời cổ đại","soHuu":[],"blurb":"Loại cốt văn xuất hiện trong truyền thuyết thời cổ đại, mạnh hơn cốt văn thường nhiều lần.","detail":"Thiên Cốt Văn là loại cốt văn xuất hiện trong truyền thuyết thời cổ đại, mạnh hơn cốt văn mà Thạch Vân Phong nghiên cứu nhiều lần. Gợi mở một hướng phát triển sức mạnh cao hơn về sau.","nguon":["@c0002"]},{"id":"tien-phap-cung-ten","name":"Tiễn pháp","loai":"khac","loaiLabel":"Kỹ năng bắn cung","phamCap":"Phàm","hePhai":"Thạch Thôn","soHuu":[],"blurb":"Kỹ năng bắn tên do cha của lũ trẻ trong thôn dạy.","detail":"Tiễn pháp là kỹ năng bắn tên do cha của lũ trẻ trong Thạch Thôn dạy; lũ trẻ cho rằng hữu ích hơn việc học cốt văn kỳ cục.","nguon":["@c0002"]},{"id":"tay-le","name":"Tẩy lễ","loai":"bi-thuat","loaiLabel":"Nghi thức tôi luyện","phamCap":"Không rõ","hePhai":"Các tộc mạnh","soHuu":[],"blurb":"Nghi thức tôi luyện thân thể quan trọng dành cho trẻ thiên tư khi lên năm tuổi.","detail":"Lần tẩy lễ đầu tiên và quan trọng nhất được cử hành cho trẻ thiên tư khi tròn năm tuổi. Đứa trẻ bị phong kín trong lô đồng, dùng nhiều thánh dược và chân huyết thái cổ để tôi luyện thân thể, tăng cường tiềm chất. Nghi thức ảnh hưởng sâu tới căn cơ và thành tựu tu hành về sau. Thạch Vân Phong đang chuẩn bị tẩy lễ cho Thạch Hạo dù Thạch Thôn thiếu các vật quý này.","nguon":["@c0006"]},{"id":"te-to-khi","name":"Tế Tổ Khí","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Thạch Thôn","soHuu":["Thạch Lâm Hổ"],"blurb":"Thuật kích hoạt Tổ Khí bằng cốt văn, dung hợp cục xương hung thú vào cơ thể người tế để phát uy áp như vua vạn thú.","detail":"Thuật tế bảo khí lưu truyền trong Thạch Thôn. Khi thúc giục, tay trái người tế nổi lên cốt văn rực rỡ, ấn cục xương tay hung thú (Tổ Khí) lên tay; cục xương dung hợp vào cánh tay thành một bộ phận của cơ thể, huyết nhục dung hòa, ngưng thành phù hiệu cổ xưa như hung thú sắp nhảy ra. Lúc kích hoạt phát một luồng hơi thở như vua vạn thú sống lại, chấn động khiến hung cầm bay lên xa. Thạch Lâm Hổ dùng thuật này đẩy lui Thanh Lân Ưng.","nguon":["@c0009"]},{"id":"bi-cot-bao-thu","name":"Bí Cốt Bảo Thư","aliases":["Bí cốt bảo thư","phù văn nguyên thủy","bảo phù"],"loai":"cong-phap","loaiLabel":"Phù văn nguyên thủy","phamCap":"Cực phẩm","hePhai":"Thái Cổ Ma Cầm","soHuu":["Thạch Hạo","Tử Vân"],"blurb":"Phù văn do bảo huyết Thái Cổ Ma Cầm sinh ra trong cơ thể Thanh Lân Ưng, sánh ngang một bộ cốt thư cực mạnh, là bí mật bất truyền.","detail":"Phù văn nguyên thủy do bảo huyết Thái Cổ Ma Cầm kết thành, thuộc riêng chủng tộc, quý hơn cốt văn thông thường. Tử Vân xảy ra hiện tượng phản tổ, kế thừa một phần ấn ký Thái Cổ Ma Cầm nên phù văn trong cơ thể được coi là Bí cốt bảo thư. Thạch Hạo nghiên cứu, đối chiếu phù văn ba chim non rồi lĩnh ngộ và thi triển: phóng vầng trăng khuyết chém đứt đại thụ, phóng vầng trăng sáng chém đôi tảng đá lớn cao năm sáu mét với mặt cắt bằng phẳng. Trên vầng trăng bạc còn ẩn một cái cây và một tòa cung điện chưa hiện ra được. Chủng tộc Thái Cổ càng hùng mạnh càng không cho phù văn truyền ra, kẻ sở hữu sẽ bị truy sát toàn lực.","nguon":["@c0012"]},{"id":"thuat-cam-mau-ky-hieu","name":"Thuật cầm máu bằng ký hiệu","loai":"bi-thuat","loaiLabel":"Bí thuật trị thương","hePhai":"Thạch Thôn","soHuu":["Thạch Vân Phong"],"blurb":"Bí thuật của tộc trưởng Thạch Thôn: ấn lòng bàn tay lóe hào quang, ký hiệu sáng như sao lên vết thương để cầm máu và khép miệng vết thương.","detail":"Thạch Vân Phong dùng khi cứu chữa Thạch Thủ Sơn: rút mũi tên sắt ra rồi ấn lòng bàn tay lóe hào quang, ký hiệu sáng lên như sao xuống vết thương, khiến máu ngừng chảy và miệng vết thương khép lại.","nguon":["@c0013"]},{"id":"cot-van-van-lac","name":"Cốt Văn (văn lạc)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Sức mạnh thần bí của Thạch Hạo","soHuu":["Thạch Hạo"],"blurb":"Sức mạnh huyền bí Thạch Hạo dùng, hiện ký hiệu/phù hiệu lóe lên trong lòng bàn tay khi dùng sức.","detail":"Sức mạnh thần bí Thạch Hạo vận dụng: khi dùng sức, ký hiệu/phù hiệu lóe lên trong lòng bàn tay, tạo được quỹ tích phát sáng chém đứt trường mâu, và tạo vầng trăng lưỡi liềm bằng văn lạc từ ngón tay phóng điểm sáng khuếch tán đánh vỡ tên nỏ. Người ngoài không tin đứa bé mò ra huyền bí của Cốt Văn, lầm tưởng là do một Bảo Cụ quý hiếm.","nguon":["@c0015"]},{"id":"ky-hieu-tay-toa-anh-sang","name":"Ký hiệu tay tỏa ánh sáng","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thủ đoạn đặc biệt của nhóc tỳ Thạch Hạo: một tay tỏa ánh sáng với ký hiệu chuyển động, đánh trọng thương đối thủ.","detail":"Khi chiến đấu với Bái Phong, Thạch Hạo dùng một tay tỏa ánh sáng cùng ký hiệu chuyển động đánh vào ngực khiến đối thủ ứa máu trọng thương. Nguồn gốc thủ đoạn này chưa được giải thích rõ.","nguon":["@c0016"]},{"id":"nguyen-thuy-bao-phu","name":"Nguyên Thủy Bảo Phù","loai":"bi-thuat","loaiLabel":"Bảo phù","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Bảo phù được khắc trên bộ xương Thái Cổ Di Chủng, được ví như mở kho báu động trời.","detail":"Nếu khắc Nguyên Thủy Bảo Phù trên bộ xương của Toan Nghê Thái Cổ Di Chủng sau khi rút chân huyết thì như mở được một kho báu động trời.","nguon":["@c0016","@c0020"],"aliases":["ký hiệu nguyên thủy","Ký hiệu nguyên thủy"]},{"id":"bao-thuat-vang-trang-bac","name":"Bảo Thuật (vầng trăng bạc)","loai":"than-thong","loaiLabel":"Thần thông / Bảo Thuật","phamCap":"Bảo Thuật","soHuu":["Thạch Hạo"],"blurb":"Thủ đoạn tấn công mạnh phát ra từ Nguyên Thủy Bảo Phù của Thái Cổ Ma Cầm, hiện thành vầng trăng bạc cắt đứt đá.","detail":"Bảo Thuật thai nghén từ Nguyên Thủy Bảo Phù, được các bộ tộc lớn quý trọng giữ kín. Khi Thạch Hạo triệu ra, một vầng trăng bạc hoàn chỉnh treo sau đầu, bên trong có cung điện và gốc cây cùng tiếng chim kêu; trăng bạc bay ra cắt đứt liền ba tảng đá lớn năm sáu mét. Đây là lần đầu tiên Thạch tộc có được một môn Bảo Thuật.","nguon":["@c0017"]},{"id":"trang-bac-thach-hao","name":"Trăng bạc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Vầng trăng bạc hiện trong lòng bàn tay, vòng tròn thần thánh phát hào quang, sắc bén dùng để chém đứt sừng và đầu địch.","detail":"Một vầng trăng bạc do Thạch Hạo triển khai trong lòng bàn tay, tạo thành vòng tròn thần thánh tỏa hào quang. Trên mặt trăng thấp thoáng có cung điện và cổ thụ. Uy lực sắc bén: dùng để chém đứt sừng và chém đầu Sơn Miêu làm đôi khi con này phục kích từ sau lưng, cũng dùng đánh bay Huyết Điêu khi nó tập kích cổ Thanh Lân Ưng.","nguon":["@c0019"]},{"id":"vang-trang-mau-xanh","name":"Vầng trăng màu xanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Nguyên Thủy Bảo Thuật","soHuu":["Thanh Lân Ưng"],"blurb":"Vầng trăng xanh đường kính hơn hai mét do Thanh Lân Ưng nhổ ra, thuộc Nguyên Thủy Bảo Thuật, chém đứt đầu cự thú.","detail":"Một vầng trăng màu xanh đường kính hơn hai mét do Thanh Lân Ưng nhổ ra từ miệng, thuộc hệ Nguyên Thủy Bảo Thuật. Cực kỳ sắc bén: trực tiếp chặt đứt đầu con Quỳ Thú dài hai mươi mét khiến máu tươi bắn cao mười mấy mét, đồng thời dùng đuổi chém Tử Kim Xà trong trận tranh đoạt di thể Toan Nghê.","nguon":["@c0019"]},{"id":"nguyen-thuy-bao-thuat","name":"Nguyên Thủy Bảo Thuật","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật tạo ra vầng trăng bạc để công thủ; đột phá thêm tầng thì hai trăng bạc hợp thành con ma cầm.","detail":"Bí thuật nhóc tỳ nắm giữ, tạo ra vầng trăng bạc để tấn công và phòng thủ. Ở chương 24, nhóc tỳ đột phá thêm một tầng, hai trăng bạc hợp lại hóa thành con ma cầm, đánh bại Bảo cụ 42 răng thú của Bái Phong, khiến răng thú rơi rụng.","nguon":["@c0024","@c0056"]},{"id":"xich-than-rang-xanh","name":"Xích thần ráng xanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tế Linh","soHuu":["Tế Linh"],"blurb":"Cành non của cây liễu Tế Linh hóa thành sợi xích thần màu ráng xanh dài hơn một dặm, nhanh như chớp vọt tới tấn công.","detail":"Khi tộc nhân cầu khẩn Tế Linh ra tay bảo vệ thôn làng khỏi con Bái dữ, thực thể bảo hộ mang hình cây liễu lớn cháy đen chỉ còn một cành non khiến chồi non động đậy, hóa thành một sợi xích thần ráng xanh kéo dài hơn một dặm, nhanh như chớp vọt tới. Đòn ra tay chặn con Bái dữ ngay trước thôn khi nó muốn dốc toàn lực tấn công tộc nhân.","nguon":["@c0026"]},{"id":"an-ky-nguyen-thuy","name":"Ấn ký nguyên thủy","loai":"khac","loaiLabel":"Nguồn gốc phù văn","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Ấn ký gốc của các chủng tộc mà Cốt văn của tộc Người mô phỏng theo.","detail":"Ấn ký nguyên thủy là dấu ký nguồn cội của các chủng tộc. Cốt văn của tộc Người bắt chước theo những ấn ký này mà khai sáng, nhưng đó chỉ là thủ đoạn, cuối cùng phải biến thành sức mạnh của chính mình.","nguon":["@c0028"]},{"id":"bao-thuat-nguyen-thuy","name":"Bảo thuật nguyên thủy","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cốt văn","soHuu":["Thạch Hạo"],"blurb":"Thuật gốc dùng Cốt văn, hao tổn tinh khí lớn.","detail":"Thuật gốc vận dụng Cốt văn, hao tổn tinh khí lớn khi thi triển; ở giai đoạn đặc thù nếu dùng quá sức sẽ gây thương tổn nghiêm trọng thân thể. Chí cường giả Nhân tộc sinh Thánh cốt và Ấn ký nguyên thủy sẽ có Bảo thuật nguyên thủy riêng của mình.","nguon":["@c0029"]},{"id":"bao-thuat-an-ky-toan-nghe","name":"Bảo Thuật (ấn ký Toan Nghê)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo Thuật chí cường","hePhai":"Thái Cổ Di Chủng","soHuu":[],"blurb":"Bảo Thuật chí cường được lưu giữ trong ấn ký nguyên thủy trên xương trán Toan Nghê.","detail":"Toan Nghê — Thái Cổ Di Chủng — trước khi chết thường tự xóa ấn ký để tránh rơi vào tay tộc khác, nhưng do phải đánh nhau với Ly Hỏa Ngưu Ma và Ác Ma Viên nên không kịp xóa, để lại phù hiệu ấn ký nguyên thủy còn chảy một loại sức mạnh thần bí. Đây là Bảo Thuật chí cường có thể tham ngộ sau khi Thạch Hạo hoàn thành tẩy lễ.","nguon":["@c0031"]},{"id":"bao-thuat-ma-cam-thai-co","name":"Bảo thuật Ma cầm Thái cổ","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"","soHuu":["Nhóc tỳ"],"blurb":"Bảo thuật nhóc tỳ được dặn học trước khi lĩnh ngộ Bảo thuật Toan Nghê.","detail":"Bảo thuật Ma cầm thời Thái cổ; tộc trưởng dặn nhóc tỳ học trước để làm nền tảng cho việc lý giải phù văn Toan Nghê phức tạp về sau.","nguon":["@c0033"]},{"id":"ao-nghia-loi-dien","name":"Ảo nghĩa Lôi Điện","cn":"","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Bí mật bất truyền","hePhai":"Lôi Tộc","soHuu":["Lôi Minh Viễn"],"blurb":"Bí mật bất truyền của Lôi Tộc, ký hiệu kỳ lạ ở lòng bàn tay hóa điện mang đen, triệu hung điểu trong điện quang.","detail":"Ảo nghĩa Lôi Điện là bí mật bất truyền của Lôi Tộc. Khi thi triển, ký hiệu kỳ lạ hiện ở lòng bàn tay, hóa thành điện mang đen và triệu hung điểu xuất hiện trong điện quang. Lôi Minh Viễn dùng bảo thuật này trong cuộc hỗn chiến ba thiên tài gần Thạch Thôn.","nguon":["@c0034"]},{"id":"bao-thuat-tran-toc-tu-son","name":"Bảo Thuật trấn tộc Tử Sơn","cn":"","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Trấn tộc","hePhai":"Tử Sơn Tộc","soHuu":["Tử Sơn Côn"],"blurb":"Bảo Thuật thuộc dòng họ Tử Sơn, phun ánh sáng hóa thái dương màu tím, triệu Hỏa Lân; tu tới cùng có thể rung chuyển nhật nguyệt sơn hà.","detail":"Bảo Thuật trấn tộc Tử Sơn là truyền thừa của dòng họ Tử Sơn. Khi thi triển phun ra ánh sáng hóa thành thái dương màu tím và triệu ra Hỏa Lân. Tương truyền tu luyện tới cùng có thể rung chuyển nhật nguyệt sơn hà. Tử Sơn Côn dùng bảo thuật này trong cuộc hỗn chiến gần Thạch Thôn.","nguon":["@c0034"]},{"id":"bao-thuat-thai-co-hung-giao","name":"Bảo Thuật Thái Cổ Hung Giao","cn":"","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Truyền thừa Thái Cổ","hePhai":"La Phù Đại Trạch","soHuu":["Giao Bằng"],"blurb":"Truyền thừa từ mảnh vỡ ấn ký của một Thái Cổ Hung Giao chân chính, tổ tiên La Phù Đại Trạch lấy được; hóa con Giao xám tro cổ xưa tham chiến.","detail":"Bảo Thuật Thái Cổ Hung Giao được truyền thừa từ mảnh vỡ ấn ký của một Thái Cổ Hung Giao chân chính, do tổ tiên La Phù Đại Trạch lấy được. Khi thi triển hóa thành con Giao xám tro cổ xưa tham chiến. Giao Bằng dùng bảo thuật này đấu một địch hai trong cuộc hỗn chiến gần Thạch Thôn.","nguon":["@c0034"]},{"id":"tao-luc-phu-van","name":"Tá Lực Phù Văn","loai":"bi-thuat","loaiLabel":"Phù văn hỗ trợ","hePhai":"Lôi Tộc","soHuu":["Lôi Minh Viễn","Lôi Hầu"],"blurb":"Phù văn hỗ trợ do Lôi Hầu sáng tạo, giúp tay phát sáng chống lực không bị gãy.","detail":"Do Lôi Hầu sáng tạo cho Lôi Tộc. Khi Lôi Minh Viễn trúng đòn nặng của Thạch Hạo, Tá Lực Phù Văn khiến tay nó phát sáng, chống lực nên không bị gãy.","nguon":["@c0038"]},{"id":"hung-tien-hung-giao-tien","name":"Hung Tiễn (Hung Giao Tiễn)","cn":"","loai":"than-thong","loaiLabel":"Bảo Thuật","phamCap":"","hePhai":"La Phù Đại Trạch","soHuu":["Giao Bằng"],"blurb":"Bảo Thuật của Giao Bằng, diễn hóa Hung Giao thành mũi tên đặt trên dây cung bắn lén.","detail":"Một chiêu Bảo Thuật của Giao Bằng: diễn hóa Hung Giao thành ‘Hung Tiễn’ (Hung Giao Tiễn) đặt lên dây cung, bắn lén sau gáy Thạch Hạo dù vừa được tha mạng. Mũi Phù Tiễn này bị Thạch Hạo xoay người tạo hai vầng trăng hợp thành cối xay trắng nghiền nát.","nguon":["@c0039"]},{"id":"phu-van-thong-thien-la-phu","name":"Phù văn thông thiên","loai":"bi-thuat","loaiLabel":"Bí thuật","hePhai":"La Phù Đại Trạch","soHuu":[],"blurb":"Bí thuật của cường giả La Phù Đại Trạch: lòng bàn tay phát sáng phù văn tạo vùng sáng bao phủ, hiện hư ảnh chim cổ đại và hung thú.","detail":"Hơn chục cường giả La Phù Đại Trạch cùng thi triển, lòng bàn tay phát sáng phù văn lấp lóe tạo vùng sáng bao phủ toàn thôn để đánh giết cây liễu, kèm hư ảnh chim cổ đại và hung thú hóa hình. Tuy nhiên đều bị Liễu Thần chém giết trong một hơi thở.","nguon":["@c0040"]},{"id":"suc-manh-te-tu","name":"Sức mạnh tế tự","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Tiên dân Thượng cổ","soHuu":[],"blurb":"Sức mạnh kỳ dị sản sinh khi người Thạch thôn tế bái thành kính dưới cây liễu, cộng minh cùng trời đất.","detail":"Theo truyền thuyết tiền dân Thượng cổ, người Thạch thôn mang tế phẩm đứng dưới gốc cây liễu tế bái thành kính thì sản sinh một loại sức mạnh kỳ dị cộng minh cùng trời đất. Cái đỉnh thuốc màu đen tổ tiên truyền lại rung nhẹ theo, hình điêu khắc rõ hơn và tỏa ánh sáng yếu ớt. Tiếc là người Thạch thôn chưa biết vận dụng loại sức mạnh này.","nguon":["@c0041"]},{"id":"bao-thuat-cot-van-hoa-lua","name":"Bảo thuật (Cốt văn hóa lửa)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":[],"blurb":"Bảo thuật khiến Cốt văn lan tràn hóa thành luồng lửa từ trên không đáp xuống.","detail":"Một cường giả trong đội liên hợp dùng Bảo thuật này khi đối đầu Gấu lông vàng kim: Cốt văn lan tràn hóa thành một luồng lửa từ trên không giáng xuống đối thủ.","nguon":["@c0042"]},{"id":"bao-thuat-hoa-hung-giao","name":"Bảo Thuật hóa Hung Giao","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"La Phù Đại Trạch","soHuu":["Chủ nhân La Phù Đại Trạch"],"blurb":"Thúc huyết tinh hóa hình một con Hung Giao khổng lồ thoát ra khỏi lưng để tấn công.","detail":"Chủ nhân La Phù Đại Trạch thúc huyết tinh dùng Bảo Thuật hóa hình một con Hung Giao khổng lồ to một trượng, dài hơn hai trăm trượng, màu tro, thoát ra khỏi lưng nhào về Thạch Thôn phun hào quang đánh vỡ đá núi, nứt mặt đất.","nguon":["@c0043"]},{"id":"bao-thuat-loi-quang-loi-hau","name":"Bảo Thuật lôi quang (Lôi Hầu)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi Tộc","soHuu":["Lôi Hầu"],"blurb":"Loạt tia chớp màu đen bổ xuống, người thi triển hóa thân thành Lôi Thần.","detail":"Lôi Hầu dùng Bảo Thuật tung loạt tia chớp màu đen bổ xuống, hóa thân thành Lôi Thần, thanh âm có lực xuyên thấu mạnh, chặn đánh cành liễu phòng ngự của Thạch Thôn.","nguon":["@c0043"]},{"id":"lot-da-hoa-chan-than-kim-lang","name":"Lột da hóa chân thân (Kim Lang)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Bộ lạc Kim Lang","soHuu":[],"blurb":"Con Tế Linh Kim Lang lột lớp da vàng cũ, lộ chân thân Thần Lang óng ánh như vàng ròng.","detail":"Con Tế Linh Kim Lang lột da: lưng nứt khe vàng, con Thần Lang óng ánh như vàng ròng chui ra khỏi lớp da cũ, hiện chân thân mạnh mẽ hơn.","nguon":["@c0043"]},{"id":"loc-xoay-thong-thien-cay-lieu","name":"Lốc xoáy thông thiên","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cây liễu (thần vật Thạch thôn)","soHuu":["Cây liễu"],"blurb":"Cành non cây liễu khuấy tạo vòng xoáy xanh lục thông thiên cuốn nuốt kẻ địch.","detail":"Thần thông của cây liễu: cành non khuấy động không gian tạo thành vòng xoáy xanh lục thông thiên, cuốn Tử Sơn Hầu vào trong xoắn xé nát bấy.","nguon":["@c0044"]},{"id":"thien-dia-hong-lo-thon-thien-tuoc","name":"Thiên Địa Hồng Lô","loai":"than-thong","loaiLabel":"Bảo Thuật","phamCap":"Chí tôn sinh linh","hePhai":"Thôn Thiên Tước","soHuu":["Thôn Thiên Tước"],"blurb":"Bảo Thuật của Thôn Thiên Tước, dùng ngàn vạn lông đen ngưng luyện ký hiệu thành một cái lò đen khổng lồ.","detail":"Thôn Thiên Tước vỗ cánh tung ngàn vạn lông đen ngưng luyện ký hiệu, biến thành một cái lò đen khổng lồ lớn hơn hàng ngàn hàng vạn ngọn núi, phát ra tiếng ‘ông’ để hút sinh linh và đối thủ vào trong.","nguon":["@c0049"]},{"id":"tien-kiem-kim-quang-mat-doc","name":"Tiên Kiếm kim quang từ mắt dọc mi tâm","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chí tôn sinh linh","soHuu":[],"blurb":"Sinh linh cầm côn mở mắt dọc giữa trán, phát kim quang hóa Tiên Kiếm chém Hồng Lô đen.","detail":"Sinh linh cầm côn sắt mở con mắt dọc giữa mi tâm, phát ra kim quang ký hiệu ngập trời, thai nghén hóa thành một thanh Tiên Kiếm tuyệt thế chém về phía Thiên Địa Hồng Lô đen của Thôn Thiên Tước.","nguon":["@c0049"]},{"id":"than-hoa-hoa-tien-kiem-do","name":"Thần hỏa hóa Tiên Kiếm đỏ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chí tôn sinh linh","soHuu":["Tiểu Hồng"],"blurb":"Chim đỏ há mồm phun hào quang mang thần hỏa ngập trời, thai nghén thành Tiên Kiếm màu đỏ.","detail":"Con chim tước đỏ há mồm phun ra hào quang mang thần hỏa ngập trời, thai nghén ngưng thành một thanh Tiên Kiếm màu đỏ, dùng để giao đấu hung thú mắt xanh khổng lồ.","nguon":["@c0049"]},{"id":"vo-thuong-dai-phap-lieu-than","name":"Vô thượng đại pháp của Liễu Thần","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Liễu Thần (cây liễu đầu thôn)","soHuu":["Liễu Thần"],"blurb":"Đại pháp cây liễu đầu thôn thi triển đưa Thạch Thôn thoát Đại Hoang, chuyển cả thôn vào không gian kỳ lạ rồi ra vùng đất mới.","detail":"Vô thượng đại pháp do Liễu Thần thi triển để cứu cả Thạch Thôn khỏi thú triều dâng trào ở Thương Mãng Sơn Mạch, đưa cả thôn vào một không gian kỳ lạ mờ sương rồi ra vùng đất mới trù phú. Sau khi thi triển, cây liễu vỏ cháy đen nứt nẻ, cành liễu non mất đi vẻ xanh biếc.","nguon":["@c0050"]},{"id":"bao-thuat-ba-dau-sau-tay","name":"Bảo Thuật ba đầu sáu tay","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Vô thượng (truyền thuyết cổ đại)","hePhai":"Thái Cổ","soHuu":["Chu Yếm (quả cầu vàng)"],"blurb":"Bảo Thuật chí cường vô thượng trong truyền thuyết thời cổ đại, biến sinh linh thành ba đầu sáu tay; khi thu lại trở về một đầu hai tay bình thường.","detail":"Sinh linh Chu Yếm dùng Bảo Thuật này để hiện thân ba đầu sáu tay. Khi lột xác thu Bảo Thuật lại, nó trở về hình dạng một đầu hai tay bình thường, thu nhỏ còn hơn ba tấc. Thạch Phi Giao nhận ra đây là Bảo Thuật vô thượng trong truyền thuyết.","nguon":["@c0053"]},{"id":"ban-huyet-canh","name":"Bàn Huyết cảnh","aliases":["Bái Huyết cảnh"],"loai":"khac","loaiLabel":"Cảnh giới tu hành","phamCap":"Cảnh giới nhập môn","hePhai":"Tu hành Cốt văn","soHuu":["Thạch Hạo"],"blurb":"Bước đầu tiên của tu hành: điều động tinh huyết toàn thân dung luyện cùng Cốt văn, máu và phù văn ngưng kết hóa thần quang.","detail":"Bàn Huyết cảnh (còn gọi Bái Huyết cảnh) là bước đầu tiên của tu hành chân chính, khi thân thể và Cốt văn hợp nhất, điều động tinh huyết dung luyện cùng phù văn, máu và phù văn ngưng kết hóa thần quang, đoạt tạo hóa thiên địa cường tráng bản thân. Sơ kỳ có lực phá hoại ít nhất tám ngàn cân, trung kỳ hai mươi ngàn cân, hậu kỳ tới năm mươi ngàn cân. Một bộ lạc vạn người khó xuất một người vào cảnh này. Thạch Hạo 6 tuổi đã đạt đỉnh cao Bàn Huyết cảnh.","nguon":["@c0054","@c0065"]},{"id":"tay-le-huyet-thanh-duoc-dinh","name":"Tẩy lễ thân thể bằng huyết thanh dược đỉnh","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Không rõ","hePhai":"Cổ khí tộc / Thạch Thôn","soHuu":["Thạch Hạo"],"blurb":"Pháp môn rèn thể dùng huyết thanh vàng kim của dược đỉnh tẩy lọc thân thể.","detail":"Huyết thanh vàng kim xông vào cơ thể qua lỗ chân lông, thải chất bẩn, gây cảm giác nứt xương xoắn thịt rồi tẩm bổ thân thể; đồng thời luyện phù văn hòa trong máu thịt, mỗi giọt huyết dịch thành một phù văn. Nhóc tỳ trải qua quá trình này ròng rã một ngày một đêm rồi thêm hai ngày hai đêm, dẫn tới lột xác.","nguon":["@c0032"]},{"id":"bao-thuat-o-quang-hung-cam","name":"Ô quang phù văn (hung cầm)","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Bảo thuật","soHuu":[],"blurb":"Bảo thuật của hung cầm khổng lồ mắt đỏ, giương đôi cánh phù văn bắn ra ô quang vô tận.","detail":"Hung cầm khổng lồ mắt đỏ như trăng máu giương đôi cánh phù văn lấp lóe, bắn ra ô quang vô tận va chạm với tiên kiếm đỏ thẫm của Tiểu Hồng, tóe lửa vang trời khi hai bên huyết chiến giành Thánh vật.","nguon":["@c0047"]},{"id":"luyen-hoa-than-tinh","name":"Luyện hóa thần tính","loai":"cong-phap","loaiLabel":"Cảnh giới luyện thể","phamCap":"Không rõ","hePhai":"Cổ khí tộc","soHuu":["Nhóc tỳ"],"blurb":"Cảnh giới kỳ dị khi nhóc tỳ hòa phù văn trong máu thịt để tịnh hóa và dung nhập thần tính Di chủng Thái cổ.","detail":"Trong quá trình tẩy lễ, nhóc tỳ chìm vào cảnh giới kỳ dị: mỗi giọt huyết dịch trong thân biến thành một phù văn tựa Lô thần Vĩnh hằng, thân thể phát ánh sáng thần thánh, dẫn dắt tịnh hóa mảnh vỡ thần tính Toan Nghê thành các hạt sáng nhỏ rồi dung nhập vào bản thân.","nguon":["@c0032"]},{"id":"chim-se-do","name":"Chim sẻ đỏ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phù văn","soHuu":["Thạch Hạo"],"blurb":"Chiêu phù văn Thạch Hạo phóng ra con chim sẻ đỏ rực đốt cháy cây đại thụ.","detail":"Chiêu thức phù văn Thạch Hạo thi triển: phóng ra một con chim sẻ đỏ rực bay đi đốt cháy cây đại thụ để khoe với ba con Thanh Lân Ưng.","nguon":["@c0012"]},{"id":"bao-thuat-vang-trang-bac-thai-co-ma-cam","name":"Bảo Thuật vầng trăng bạc","aliases":["Thái Cổ Ma Cầm (Bảo Thuật)"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Nguyên Thủy Bảo Thuật","hePhai":"Nguyên Thủy Bảo Thuật","soHuu":["Tiểu Thạch Hạo"],"blurb":"Thạch Hạo vẫy tay ra ánh sáng bạc hóa vầng trăng, tinh khí hóa đại dương, từ trong trăng bạc xông ra một Thái Cổ Ma Cầm.","detail":"Bảo Thuật Nguyên Thủy do phản tổ của ba con Thanh Lân Ưng biến dị. Thái Cổ Ma Cầm hiện ra còn ở dạng ban đầu chưa hoàn chỉnh (nghi Thôn Thiên Tước hoặc Thanh Thiên Bằng), xé đứt Hung Giao và xuyên thủng đầu Hỏa Lân. Cường giả nhận định nếu diễn hóa trọn vẹn sẽ không kém thần thông trấn tộc của Tử Sơn Tộc, Lôi Tộc, La Phù Đại Trạch.","nguon":["@c0038"]},{"id":"bao-thuat-hung-giao","name":"Bảo Thuật Hung Giao","aliases":["Hôi Giao"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo Thuật","soHuu":["Giao Bằng"],"blurb":"Giao Bằng gọi từ ký tự cổ trong lòng bàn tay một con Hung Giao màu tro xám to như vại nước.","detail":"Con Hung Giao vảy chi chít, phong cách cổ tang thương như từ Thái Cổ; nhào về Thạch Hạo nhưng bị Thái Cổ Ma Cầm xé đứt.","nguon":["@c0038","@c0044"]},{"id":"bao-thuat-hoa-lan-mau-tim","name":"Bảo Thuật Hỏa Lân màu tím","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo Thuật","soHuu":["Tử Sơn Côn"],"blurb":"Tử Sơn Côn phóng thái dương màu tím chứa Hỏa Lân màu tím, liệt diễm hừng hực.","detail":"Hỏa Lân màu tím bị Thái Cổ Ma Cầm ấn chân xuyên thủng đầu, hóa thành tinh khí.","nguon":["@c0038"]},{"id":"bao-thuat-dien-quang-sam-set","name":"Bảo Thuật điện quang sấm sét","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo Thuật","soHuu":["Lôi Minh Viễn"],"blurb":"Lôi Minh Viễn bành trướng cơ thể tạo điện quang màu đen, lòng bàn tay hiện ký hiệu bắn tia chớp lớn màu đen.","detail":"Điện quang/sấm sét màu đen của Lôi Minh Viễn bị Cốt Văn của Thạch Hạo dung hóa.","nguon":["@c0038"]},{"id":"bao-thuat-hoa-lan-tim","name":"Bảo Thuật Hỏa Lân tím","loai":"than-thong","loaiLabel":"Bảo Thuật","phamCap":"Bảo Thuật","soHuu":["Tử Sơn Côn"],"blurb":"Bảo Thuật triệu thái dương màu tím chứa Hỏa Lân màu tím của Tử Sơn Côn.","detail":"Tử Sơn Côn triệu thái dương màu tím, bên trong chứa Hỏa Lân màu tím; bị Thái Cổ Ma Cầm ấn chân xuyên thủng đầu khiến Hỏa Lân vỡ nát.","nguon":["@c0038"]},{"id":"dien-quang-den","name":"Điện quang đen","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông","soHuu":["Lôi Minh Viễn"],"blurb":"Cỗ điện quang đen của Lôi Minh Viễn, tia chớp lớn màu đen đánh Thạch Hạo.","detail":"Lôi Minh Viễn tạo cỗ điện quang đen, phát ra tia chớp lớn màu đen tấn công Thạch Hạo.","nguon":["@c0038"]},{"id":"bao-thuat-toan-nghe","name":"Bảo Thuật (của Toan Nghê)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Năng lực chủng tộc Toan Nghê","soHuu":["Toan Nghê"],"blurb":"Năng lực chủng tộc mạnh mẽ của loài Toan Nghê.","detail":"Năng lực bẩm sinh của Toan Nghê Thái Cổ Di Chủng: đánh thủng lưng Ác Ma Viên một lỗ máu trước sau thông suốt, đồng thời bắn ra hai chùm ánh sáng mang theo tiếng sấm phá vỡ ký hiệu trên người Ly Hỏa Ngưu Ma.","nguon":["@c0021","@c0033","@c0036","@c0099"],"aliases":["Phù văn nguyên thủy Toan Nghê"]},{"id":"bao-thuat","name":"Bảo Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần Thông","phamCap":"","hePhai":"Đại Hoang","soHuu":["Thạch Hạo","Giao Bằng"],"aliases":[],"blurb":"Kỹ pháp cốt lõi của giới tu luyện Đại Hoang; người tu tùy lĩnh ngộ mà diễn hóa uy năng khác nhau.","detail":"Bảo Thuật là kỹ pháp cốt lõi trong Đại Hoang, mỗi người tùy thiên phú và lĩnh ngộ mà diễn hóa uy năng riêng. Thạch Hạo diễn hóa Bảo Thuật tạo hai vầng trăng giao hòa hợp thành một cái cối xay trắng tinh, nghiền nát mũi tên bắn lén của Giao Bằng; ông lão Vân Thiên Cung nhiều lần tán thưởng thiên phú diễn hóa Bảo Thuật của nhóc tỳ. Nhiều thế lực thi nhau hứa truyền dạy Bảo Thuật chí cường để chiêu mộ Thạch Hạo, trong đó có nhánh Ly Hỏa Bảo Thuật tương truyền dung luyện núi non thành biển lửa, liên hệ đạo thống Hỏa Thần Thượng Cổ. Bảo Thuật cũng là căn cơ để thi triển các dị thú như Thái Cổ Ma Cầm.","nguon":["@c0039"]},{"id":"hung-giao-tien","name":"Hung Giao Tiễn","cn":"","loai":"bi-thuat","loaiLabel":"Bí Thuật","phamCap":"","hePhai":"La Phù Đại Trạch","soHuu":["Giao Bằng"],"aliases":["Hung Tiễn","Phù Tiễn"],"blurb":"Một chiêu Bảo Thuật của Giao Bằng: diễn hóa Hung Giao thành mũi tên bắn lén đối thủ.","detail":"Hung Giao Tiễn là một chiêu Bảo Thuật của Giao Bằng (La Phù Đại Trạch): diễn hóa Hung Giao thành một mũi tên đặt trên dây cung, thừa lúc vừa được tha mạng liền bắn lén sau gáy Thạch Hạo. Nhóc tỳ xoay người, tạo hai vầng trăng hợp thành cối xay trắng nghiền nát mũi tên, khiến đòn hiểm thất bại. Chiêu này thể hiện bản tính hung hăng, vô ơn của Giao Bằng.","nguon":["@c0039"]},{"id":"loi-quang-thuat","name":"Lôi quang thuật","cn":"","loai":"bi-thuat","loaiLabel":"Lôi pháp","phamCap":"Không rõ","hePhai":"Lôi tộc","soHuu":["Lôi Hầu"],"blurb":"Lôi pháp triệu mấy chục tầng lôi quang, hóa thành quả cầu sét.","detail":"Lôi Hầu rống to triệu mấy chục tầng lôi quang công kích, có thể hóa thân thành quả cầu sét chống cự. Trước cây liễu Thạch thôn thì vô dụng: cây liễu càng hấp thu lôi quang càng xanh thẳm và mạnh lên, khiến Lôi Hầu lần đầu mất lòng tin vào bản thân.","nguon":["@c0044"]},{"id":"vong-xoay-xanh-lieu-than","name":"Vòng xoáy màu xanh","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Liễu Thần","soHuu":["Liễu Thần"],"blurb":"Vòng xoáy thông trời màu xanh do cây liễu bùng nổ, cuốn nát mọi thứ trong tầm.","detail":"Uy lực vượt xa tưởng tượng: vòng gió xoáy màu xanh gào rú như Thái Cổ Hung Thú, cuốn tan người khổng lồ màu tím thành bột, hủy Bảo Cụ, cuốn cả tộc trưởng bộ lạc Kim Lang vào mắt gió xoáy khiến thân tan thành vũng máu.","nguon":["@c0045"]},{"id":"bao-thuat-tien-kiem-tieu-hong","name":"Bảo thuật tiên kiếm đỏ thẫm","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Tiểu Hồng"],"blurb":"Bảo thuật của Tiểu Hồng: há mỏ trong suốt phun hào quang ngưng thành thanh tiên kiếm đỏ thẫm cực kỳ sắc bén.","detail":"Trong đại chiến tứ đại sinh linh, Tiểu Hồng há mỏ trong suốt phun ra hào quang hóa thành một thanh tiên kiếm đỏ thẫm sắc bén khôn tả, chém thẳng vào con hung cầm mắt đỏ. Tiên kiếm va chạm với ô quang phù văn của hung cầm tóe lửa vang trời.","nguon":["@c0047"]},{"id":"ki-tu-long-ban-tay-thach-hao","name":"Kí tự trong lòng bàn tay Thạch Hạo","loai":"khac","loaiLabel":"Năng lực bí ẩn","hePhai":"Bí ẩn thân thế Thạch Hạo","soHuu":["Thạch Hạo"],"blurb":"Kí tự bí ẩn lóe sáng trong lòng bàn tay trái Thạch Hạo khi nó chém hất mũi tên, rồi nhanh chóng lụi đi.","detail":"Khi Thạch Hạo dùng tay trái chém hất mũi tên trong trận đụng độ với Bái Thôn, lòng bàn tay trái của nó lóe lên một kí tự rồi nhanh chóng lụi đi, chỉ số ít người nhìn thấy. Đây là dấu hiệu gợi mở năng lực và bí mật thân thế của nó.","nguon":["@c0014"]},{"id":"vang-trang-bac","name":"Vầng trăng bạc","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cốt Văn","soHuu":["Thạch Hạo"],"blurb":"Đòn chém phát ra vầng trăng bạc lưỡi liềm, có thể liên tục triệu hồi vầng thứ hai khi vầng thứ nhất mờ.","detail":"Thạch Hạo dùng vầng trăng bạc chém liên tục tấn công Thử Vương trên lưng Thanh Lân Ưng, gọi ra vầng trăng bạc thứ hai khi vầng thứ nhất mờ đi. Uy lực hiệp đồng cùng ký hiệu Nguyên Thủy Bảo Phú của Thanh Lân Ưng đánh gãy xương chuột tím, khiến nó trọng thương rơi xuống.","nguon":["@c0020"]},{"id":"luyen-the-chan-huyet-bao-duoc","name":"Luyện thể bằng chân huyết hung thú và bảo dược bổ cốt","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Sơ cấp (bộ lạc)","hePhai":"Thạch Thôn","soHuu":["Thạch Thôn"],"blurb":"Cách rèn thân thể trẻ nhỏ của các bô lão Thạch Thôn bằng chân huyết hung thú và bảo dược bổ cốt.","detail":"Các bô lão Thạch Thôn định kỳ dùng chân huyết hung thú cùng bảo dược bổ cốt để luyện thể cho lũ trẻ trong thôn, giúp thân thể chúng rắn rỏi mạnh mẽ. Hiệu quả rõ rệt: đám thiếu niên sáu bảy đến mười hai mười ba tuổi đã có thể vật trâu mộng, nhấc chùy đồng trăm cân.","nguon":["@c0005"]},{"id":"bao-thuat-phu-van-nguyen-thuy-toan-nghe","name":"Bảo thuật Phù văn nguyên thủy Toan Nghê","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chí cường / ngang thần thông trấn tộc","hePhai":"Di chủng Thái cổ Toan Nghê","soHuu":[],"blurb":"Bảo thuật chí cường của Di chủng Thái cổ Toan Nghê, trân quý cực độ, sánh cùng thần thông trấn tộc của đại tộc.","detail":"Cường giả các thế lực suy ra Thạch thôn có thể chiếm được di thể một con Toan Nghê nên cất giấu Bảo thuật Phù văn nguyên thủy Toan Nghê chí cường, sánh cùng thần thông trấn tộc của đại tộc — khiến La Phù Đại Trạch, bộ lạc Kim Lang vừa run vừa đỏ mắt tham lam.","nguon":["@c0036"]},{"id":"sam-set-den-loi-minh-vien","name":"Sấm sét đen","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Lôi Tộc","soHuu":["Lôi Minh Viễn"],"blurb":"Thần thông lôi điện của Lôi Minh Viễn: bành trướng cơ thể tạo điện quang màu đen, ấn ký hiệu sấm sét bắn tia chớp lớn.","detail":"Lôi Minh Viễn khi ra tay khiến cơ thể bành trướng tạo ra một cỗ điện quang màu đen, lòng bàn tay xuất hiện một ký hiệu sấm sét đan xen, ấn về phía trước bắn ra tia chớp to lớn màu đen. Trong quyết đấu với Thạch Hạo, tia chớp bị Cốt Văn của đối thủ dung hóa thành mảng kim loại, bản thân bị đá đạp trọng thương.","nguon":["@c0038"]},{"id":"tien-phap-thap-ngu-gia","name":"Tiễn pháp của Thập Ngũ Gia","loai":"khac","loaiLabel":"Kỹ xạ tiễn","phamCap":"Không rõ","hePhai":"Cổ quốc — dòng hoàng thân","soHuu":["Thập Ngũ Gia"],"blurb":"Kỹ xạ tiễn tinh diệu của Lão Thập Ngũ: hai mũi tên hạ được một Loan Điểu hậu duệ Thái Cổ Thần Cầm.","detail":"Được trưởng bối khen sẽ làm đô thành chấn động; kết hợp cung đen dây gân Giao bắn ra mũi tên hào quang ngập trời như Giao Long. Sau này chính tay bắn chết Tỳ Hưu ở Bách Tộc Chiến Trường.","nguon":["@c0055"]},{"id":"nguyen-thuy-an-ky","name":"Nguyên thủy ấn ký","cn":"","loai":"khac","loaiLabel":"Ấn ký","phamCap":"Chí cường giả Nhân tộc","hePhai":"Nhân tộc","soHuu":[],"blurb":"Dấu ấn gốc mà một số Chí cường giả Nhân tộc rèn ra được Thánh cốt sở hữu, sinh cùng Nguyên thủy bảo thuật.","detail":"Ấn ký nguyên thủy khắc lên Thánh cốt của Chí cường giả Nhân tộc. Xuất hiện đồng thời với Nguyên thủy bảo thuật khi một chí cường giả rèn thành Thánh cốt, là một trong ba đặc trưng phân biệt tầng lớp tối cao. Với người trời sinh Chí Tôn cốt (Nguyên thủy bảo cốt) như Thạch Hạo, phù văn nguyên thủy đã sẵn có bên trong xương, khỏi cần rèn.","nguon":["@c0056"]},{"id":"bao-thuat-lien-thu-phu-the-thap-nhat-de","name":"Bảo thuật liên thủ phu thê (Thập Nhất đệ)","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật hợp kích","phamCap":"Cực điểm khi liên thủ","hePhai":"Nhân tộc — Vương hầu phủ Thập Ngũ gia","soHuu":["Thập Nhất đệ","Mẹ Thạch Hạo"],"blurb":"Hai loại Bảo thuật khác nhau của Thập Nhất đệ và vợ, khi phu thê liên thủ sẽ đạt cực điểm uy lực.","detail":"Hai vợ chồng cha mẹ Thạch Hạo mỗi người nắm giữ một loại Bảo thuật riêng. Khi hai loại Bảo thuật này liên thủ sẽ đạt đến cực điểm, uy lực tuyệt đối rất lớn — lý do người vợ khăng khăng đòi cùng chồng đi Bách tộc chiến trường tìm cứu Thập Ngũ gia dù chồng bảo ở lại chăm Hạo nhi.","nguon":["@c0056"]},{"id":"trong-dong","name":"Trọng Đồng","cn":"","loai":"than-thong","loaiLabel":"Dị đồng trời sinh","phamCap":"Thượng cổ Thánh nhân / Thần nhân","hePhai":"Nhân tộc","soHuu":["Thạch Nghị"],"blurb":"Một mắt có đến hai con ngươi — đặc thù trời sinh của Thượng cổ Thánh nhân, Thần nhân, có thể nhìn ra ngọn nguồn thế giới.","detail":"Dị đồng trời sinh: trong một con mắt có đến hai con ngươi. Chỉ Thượng cổ Thánh nhân, Thần nhân mới có; kẻ mang Trọng Đồng có thể nhìn thấu ngọn nguồn thế giới, nhìn ra bảo vật ẩn giấu trong người khác. Nhờ Trọng Đồng, Thạch Nghị vừa nhìn đã biết trong cơ thể Thạch Hạo có một khối xương ẩn chứa phù văn thâm ảo — chính là Chí Tôn cốt trời sinh. Địa vị Lục tẩu trong tộc cực cao cũng nhờ sinh ra đứa con mang Trọng Đồng. Lục tẩu tin con mình ắt phải xưng tôn khắp thiên thượng địa hạ, nên mới lập mưu cướp Chí Tôn cốt cấy thêm cho con.","nguon":["@c0056"]},{"id":"bao-thuat-kinh-thien-thach-tu-lang","name":"Bảo thuật kinh thiên (Thạch Tử Lăng)","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Chưa rõ","hePhai":"Thạch Tộc","soHuu":["Thạch Tử Lăng"],"blurb":"Bảo thuật uy lực kinh thiên của Thạch Tử Lăng, phát động qua Hoàng Kim chiến mâu, âm thanh như Chư Thiên thần linh cùng ngâm xướng chú ngôn.","detail":"Thạch Tử Lăng vung Hoàng Kim chiến mâu vạch một vòng, phát bảo thuật kinh thiên như Chư Thiên thần linh cùng ngâm xướng chú ngôn, chú ngôn ầm ầm đinh tai nhức óc. Uy lực đủ để đánh bay đám lão già ngăn cản trước mặt, khiến họ phun máu tươi và hoảng sợ. Bảo thuật này gắn liền với động tác vung chiến mâu và thần lực bậc trưởng lão của Thạch Tử Lăng — người xếp thứ 11 (lão thập nhất) trong thế hệ Thạch Tộc.","nguon":["@c0058","@c0059"]},{"id":"sam-set-vang-thach-tu-lang","name":"Sấm sét vàng (tia điện vàng từ mắt Thạch Tử Lăng)","loai":"than-thong","loaiLabel":"Thần thông","hePhai":["Thạch tộc"],"soHuu":["Thạch Tử Lăng"],"blurb":"Thần thông dị năng đặc thù của Thạch Tử Lăng — hét dài phun vô số tia điện màu vàng từ hai mắt.","detail":"Khi vận công, Thạch Tử Lăng hét dài một tiếng, hai mắt phun ra vô số tia điện màu vàng, không gian bị sấm sét chen ép nổ lớn dữ dội; kèm theo tia kim quang trong mắt đánh bay đối thủ. Trong chương dùng để đánh vỡ quạt lông Phong Lôi và trọng thương lão bề trên.","nguon":["@c0059"]},{"id":"sat-tran-phu-van-bao-cot","name":"Sát trận phù văn khóa không gian bằng bảo cốt","loai":"khac","loaiLabel":"Trận pháp","hePhai":["Thạch tộc — nhánh Thạch Nghị"],"soHuu":["Nhánh Thạch Nghị"],"blurb":"Sát trận do nhánh Thạch Nghị bố trí, dùng nhiều loại bảo cốt tạo phù văn chằng chịt như thiên la địa võng.","detail":"Bảo cốt được bố trí thành sát trận, phù văn chằng chịt trên cả mặt đất và trên không tạo thiên la địa võng khóa không gian trấn áp đối thủ. Trong chương bị Thạch Tử Lăng cầm chiến mâu vùng vẫy phá tan, bảo cốt nổ tung.","nguon":["@c0059"]},{"id":"bao-thuat-phuong-hoang-thai-co-hung-cam-huyet-hoang","name":"Bảo Thuật Phượng Hoàng – Thái Cổ Hung Cầm Huyết Hoàng","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Chí cường tông lão","hePhai":"Thạch tộc – Hoàng Đô","soHuu":["Thạch Uyên"],"blurb":"Bảo Thuật của Thạch Uyên: hai tay hóa cánh thần Phượng Hoàng lông đỏ, triệu Thái Cổ Hung Cầm Huyết Hoàng cùng chiến đấu.","detail":"Khi Thạch Uyên vận Bảo Thuật, hào quang màu tím dâng trào, hai tay hóa thành cánh thần Phượng Hoàng phủ đầy lông đỏ, phát ra tiếng phượng kêu chấn động trời đất; cánh thần va vào chiến mâu vàng của Thạch Tử Lăng như hai ngọn núi lửa đụng nhau. Tiến thêm một bước, ông ta triệu ra Thái Cổ Hung Cầm Huyết Hoàng toàn thân đỏ rực, bộ lông đẹp đẽ, quét thần quang bốn phía để giao đấu cùng bóng Thái Cổ Hung Thú của Thạch Tử Lăng. Cuối trận Thái Cổ Hung Cầm bị chiến mâu đâm chết, Thạch Uyên bị đâm xuyên vai, phế nửa cánh tay, mất chiến lực.","nguon":["@c0060"]},{"id":"bao-thuat-thai-co-hung-thu-thach-tu-lang","name":"Bảo Thuật Thái Cổ Hung Thú","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Bá tuyệt thiên địa","hePhai":"Thạch tộc – Hoàng Đô","soHuu":["Thạch Tử Lăng"],"blurb":"Bảo Thuật của Thạch Tử Lăng: triệu bóng một Thái Cổ Hung Thú khổng lồ mơ hồ che kín thiên địa, uy áp vạn linh như quân vương.","detail":"Khi đối đầu Thạch Uyên, Thạch Tử Lăng triệu hiện bóng một Thái Cổ Hung Thú khổng lồ mơ hồ, thân hình che kín thiên địa, gào thét khiến vạn linh thần phục như quân vương — được xem là một trong những con hung thú mạnh mẽ nhất. Bóng hung thú xông vào giao chiến với Thái Cổ Hung Cầm Huyết Hoàng của Thạch Uyên, đánh sụp hàng loạt cung điện quanh phụ đệ. Danh tính cụ thể của con hung thú này chưa lộ, gợi ý nguồn gốc huyết mạch đặc biệt. Cuối trận, Thạch Tử Lăng thu bóng hung thú thành ký hiệu Thái Cổ Hung Thú dung nhập cơ thể.","nguon":["@c0060"]},{"id":"bao-thuat-ky-hieu-xuyen-phong-ngu-thach-tu-lang","name":"Bảo Thuật ký hiệu xuyên phòng ngự (Thạch Tử Lăng)","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Không rõ – ngoài kho tàng Thạch tộc","hePhai":"Chưa rõ (không có trong ghi chép Thạch tộc)","soHuu":["Thạch Tử Lăng"],"blurb":"Bảo Thuật kỳ lạ của Thạch Tử Lăng: rung tay tạo ký hiệu đan xen phức tạp, men theo chiến mâu phát ra sức mạnh thần bí có thể xuyên thẳng qua Bảo Thuật đối thủ để đánh mục tiêu phía sau.","detail":"Khi các tông lão Thạch tộc đồng loạt phóng Bảo Thuật ngập trời dựng phong tỏa tiền phương, Thạch Tử Lăng rung tay, ký hiệu đan xen phức tạp khó hiểu rơi xuống men theo chiến mâu, phát ra sức mạnh kỳ lạ. Sức mạnh thần bí này xuyên thẳng qua Bảo Thuật của tộc lão, tuy có yếu đi nhưng vẫn đánh trúng Thạch Nghị đứng phía sau, khiến hơn trăm cây xương của y gãy lìa thoáng cái, toàn thân là máu. Các tộc lão kinh hãi, khẳng định trong tộc chưa từng ghi chép loại Bảo Thuật này, gợi ý cơ duyên/xuất xứ bí ẩn phía sau Thạch Tử Lăng.","nguon":["@c0060"]},{"id":"dien-quang-sam-set-den","name":"Bảo Thuật Điện quang sấm sét đen","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi Tộc","soHuu":["Lôi Minh Viễn"],"blurb":"Thần thông lôi điện của Lôi Minh Viễn, tạo cỗ điện quang màu đen và bắn tia chớp lớn từ ký hiệu sấm sét trong lòng bàn tay.","detail":"Lôi Minh Viễn thi triển khi bị dồn ép: cơ thể bành trướng tạo ra một cỗ điện quang màu đen, lòng bàn tay hiện một ký hiệu sấm sét đan xen rồi ấn về phía trước bắn ra tia chớp to lớn màu đen. Trong trận đấu với Thạch Hạo, tia chớp đen này bị Cốt Văn dung hóa hết, còn bản thân Lôi Minh Viễn bị đá đạp trọng thương.","nguon":["@c0038"]},{"id":"ly-hoa-bao-thuat","name":"Ly Hỏa Bảo Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":[],"blurb":"Bảo Thuật hệ hỏa có thể dung luyện núi non thành biển lửa, đốt kẻ địch.","detail":"Một thế lực khoe Ly Hỏa Bảo Thuật có thể dung luyện núi non thành biển lửa, thiêu đốt kẻ địch, liên hệ tới đạo thống Hỏa Thần Thượng Cổ; dùng để dụ Thạch Hạo bái sư.","nguon":["@c0039"]},{"id":"loi-quang-loi-hau","name":"Lôi Quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Lôi Tộc","soHuu":["Lôi Hầu"],"blurb":"Sức mạnh sấm sét Lôi Hầu vận dụng khi bị cây liễu treo giữ.","detail":"Thần thông của Lôi Hầu, dùng để chống cự khi bị cây liễu treo lơ lửng; khi cạn kiệt thì thân thể khô héo rơi xuống đất mà chết.","nguon":["@c0045"]},{"id":"gio-xoay-mau-xanh-cay-lieu","name":"Gió xoáy màu xanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Liễu Thần","soHuu":["Liễu Thần"],"blurb":"Vòng xoáy thông trời màu xanh của cây liễu, cuốn nát mọi thứ.","detail":"Thần thông của cây liễu (Liễu Thần): bùng nổ thành vòng xoáy màu xanh vượt tưởng tượng, gào rống như Thái Cổ Hung Thú, cuốn nát người khổng lồ màu tím, tộc trưởng Kim Lang và các cường giả vây thành.","nguon":["@c0045"]},{"id":"xich-than-trat-tu","name":"Xích thần trật tự","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Trận pháp phòng ngự","phamCap":"","hePhai":"Thạch thôn (cây liễu)","soHuu":["Liễu Thần"],"blurb":"Các cọng sáng đan vào nhau chói lọi do cây liễu cổ Thạch thôn dệt ra, bao phủ toàn thôn để tự bảo vệ.","detail":"Khi đại chiến lan tới Thạch thôn, cây liễu cháy đen phát ánh sáng xanh, dệt ra Xích thần trật tự — vô số cọng sáng đan nhau bao phủ toàn bộ Thạch thôn, khiến cả thôn bỗng dưng biến mất khỏi trời đất. Đây là thần thông phòng ngự tự bảo vệ, không dùng để đại chiến vì cây liễu đã bị trọng thương mang tính hủy diệt.","nguon":["@c0048"]},{"id":"bao-thuat-lien-thu-phu-the","name":"Bảo thuật liên thủ phu thê","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật hợp kích","phamCap":"Uy lực cực điểm khi song tu hợp kích","hePhai":"Nhân tộc — Vương hầu phủ","soHuu":["Thập Nhất đệ","Mẹ Thạch Hạo"],"blurb":"Hai loại Bảo thuật khác nhau của cha mẹ Thạch Hạo, khi liên thủ đạt tới cực điểm với uy lực tuyệt đối.","detail":"Cha Thạch Hạo (Thập Nhất đệ) và vợ mỗi người sở hữu một loại Bảo thuật riêng biệt. Khi hai loại Bảo thuật này phối hợp liên thủ thì uy lực đạt tới cực điểm, mạnh hơn hẳn so với thi triển đơn lẻ. Chính vì lý do đó mà người vợ nhất quyết đòi cùng chồng tới Bách tộc chiến trường tìm Thập Ngũ gia, cho rằng phu thê hợp lực mới phát huy trọn vẹn sức mạnh.","nguon":["@c0056"]},{"id":"bi-phap-cay-chi-ton-cot","name":"Bí pháp cấy Chí Tôn Cốt","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thạch Tộc","soHuu":["Bóng đen (u linh)"],"blurb":"Bí pháp dùng ký hiệu chư thiên moi và cấy Chí Tôn Cốt sang cơ thể khác, khép vết thương cầm máu.","detail":"Ký hiệu lấp lóe khiến mật thất sục sôi thần huy, lôi sơn hàng lâm, thiểm điện và thần âm ầm ầm; cuối cùng ký hiệu ngưng tụ thành một miếng Chí Tôn Cốt ẩn vào lồng ngực đối tượng, đồng thời khép vết thương cầm máu. Bóng đen dựa vào Cốt Thư để thực hiện.","nguon":["@c0057"]},{"id":"bi-phap-rut-chan-huyet","name":"Bí pháp rút chân huyết","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","soHuu":["Bóng đen (u linh)"],"blurb":"Bí pháp dùng bình ngọc và ký hiệu để hút chân huyết còn sót trong cơ thể, tẩm bổ Chí Tôn Cốt.","detail":"Bóng đen dùng bình ngọc, ký hiệu lấp lóe hút cạn chân huyết còn sót trong cơ thể Thạch Hạo; ánh sáng mơ hồ khiến mật thất thần thánh. Việc rút chân huyết khiến nạn nhân không sống quá hai tuổi.","nguon":["@c0057"]},{"id":"bao-thuat-hoang-kim-chien-mau","name":"Bảo thuật Hoàng Kim chiến mâu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thạch Tộc","soHuu":["Thạch Tử Lăng"],"blurb":"Bảo thuật kinh thiên phát ra từ Hoàng Kim chiến mâu của Thạch Tử Lăng, chú ngôn vang như Chư Thiên thần linh cùng ngâm xướng.","detail":"Bảo thuật thần thông của Thạch Tử Lăng khi vận Hoàng Kim chiến mâu. Hắn vung chiến mâu vạch một vòng, phát ra bảo thuật kinh thiên tựa Chư Thiên thần linh cùng ngâm xướng chú ngôn, tiếng ầm ầm đinh tai nhức óc, uy lực đánh bay cả đám lão già ngăn cản khiến họ phun máu tươi, hoảng sợ. Khi đâm ra, thần quang vạn trượng, vô số phù văn kết thành cây chiến mâu bằng ánh sáng, đủ sức bẻ gãy binh khí và nghiền nát bảo cụ của đối phương, xuyên thủng lồng ngực người thanh niên chú ruột của Nghị nhi khiến hắn bay xa cắm vào cửa một tòa cung điện.","nguon":["@c0058"]},{"id":"bao-thuat-phuong-hoang-thai-co-hung-cam","name":"Bảo Thuật Phượng Hoàng · Thái Cổ Hung Cầm Huyết Hoàng","cn":"","loai":"than-thong","loaiLabel":"Bảo Thuật","phamCap":"Bảo Thuật chí cường của tông lão","hePhai":"Thạch tộc Hoàng Đô","soHuu":["Thạch Uyên"],"blurb":"Bảo Thuật hàng tông lão: hai tay hóa cánh thần Phượng Hoàng và triệu Thái Cổ Hung Cầm Huyết Hoàng.","detail":"Khi vận Bảo Thuật, hào quang tím dâng trào, hai tay Thạch Uyên hóa thành cánh thần Phượng Hoàng lông đỏ, phát tiếng phượng kêu chấn động trời đất. Tiến thêm một bước có thể triệu ra Thái Cổ Hung Cầm Huyết Hoàng toàn thân đỏ rực, bộ lông đẹp đẽ, lao xuống công kích. Là Bảo Thuật chí cường của hàng tông lão Thạch tộc.","nguon":["@c0060"]},{"id":"trung-dong-thach-nghi","name":"Trùng đồng","cn":"","loai":"than-thong","loaiLabel":"Thần thông thiên phú","phamCap":"Thiên phú","hePhai":"Thạch tộc Hoàng Đô","soHuu":["Thạch Nghị"],"blurb":"Con mắt ẩn hai con ngươi của Thạch Nghị, nhìn thấu bổn nguyên vạn vật và phát hiện nhược điểm đối thủ.","detail":"Trong mắt Thạch Nghị ẩn chứa hai con ngươi, có thể nhìn thấu bổn nguyên của vạn vật, phát hiện khe hở và nhược điểm trên người đối thủ lẫn hung thú Bảo Thuật. Trong trận, Thạch Nghị ba lần chỉ điểm nhược điểm cho Thạch Uyên đánh vào sườn trái, dưới nách trái và ngực hung thú, song hạn chế là chỉ điểm không kịp tốc độ Bảo Thuật của Thạch Tử Lăng.","nguon":["@c0060","@c0061","@c0062"]},{"id":"bao-thuat-ky-hieu-xuyen-phong-ngu","name":"Bảo Thuật ký hiệu xuyên phòng ngự","cn":"","loai":"than-thong","loaiLabel":"Bảo Thuật","phamCap":"Bí ẩn, không có trong ghi chép Thạch tộc","hePhai":"Không rõ","soHuu":["Thạch Tử Lăng"],"blurb":"Bảo Thuật ký hiệu kỳ lạ của Thạch Tử Lăng, xuyên thẳng qua thân thể lẫn Bảo Thuật đối thủ để đánh mục tiêu phía sau.","detail":"Thạch Tử Lăng rung tay tạo ra các ký hiệu đan xen phức tạp khó hiểu, men theo chiến mâu phóng ra sức mạnh thần bí. Sức mạnh này có thể xuyên thẳng qua thân thể và Bảo Thuật phong tỏa của cả đám tộc lão để đánh trúng mục tiêu, tuy có yếu đi nhưng vẫn giữ uy lực. Các tộc lão khẳng định trong tộc chưa từng ghi chép loại Bảo Thuật này, gợi ý xuất xứ bí ẩn của Thạch Tử Lăng.","nguon":["@c0060"]},{"id":"thai-co-hung-thu-huyen-anh","name":"Thái cổ hung thú (huyễn ảnh)","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật / huyết mạch","phamCap":"","hePhai":"","soHuu":["Thạch Tử Lăng"],"blurb":"Thạch Tử Lăng hiện hung thú Thái cổ từ cơ thể để cùng đánh giết.","detail":"Thạch Tử Lăng dùng bảo thuật hiện huyễn ảnh hung thú Thái cổ từ cơ thể, đồng đánh giết khi một mình áp đảo bốn tông lão Thạch tộc trong trận đòi công đạo.","nguon":["@c0062"]},{"id":"tam-huu-linh-te-nhat-diem-thong","name":"Tâm hữu linh tê nhất điểm thông","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật hợp lực","phamCap":"","hePhai":"","soHuu":["Thạch Tử Lăng","Vợ Thạch Tử Lăng"],"blurb":"Bảo thuật hợp lực phu thê, chấn động cả Hoàng Đô.","detail":"Mẹ nhóc tỳ ôm con giết vào chiến trường, hợp lực Thạch Tử Lăng tế ra bảo thuật này, uy lực chấn động cả Hoàng Đô.","nguon":["@c0062"]},{"id":"tran-phong-tu-phuong","name":"Trấn phong tứ phương","cn":"","loai":"khac","loaiLabel":"Trận / thủ đoạn phong tỏa","phamCap":"","hePhai":"","soHuu":["Bốn vị lão tổ Thạch tộc"],"blurb":"Thủ đoạn phong tỏa của bốn lão tổ, khóa chặt Thạch phủ.","detail":"Bốn lão tổ Thạch tộc trấn phong tứ phương, phong tỏa Thạch phủ ngay khi vợ chồng Thạch Tử Lăng bước vào, chuẩn bị sẵn để trấn áp.","nguon":["@c0062"]},{"id":"nguyen-thuy-chan-giai-cot-van","name":"Nguyên Thủy Chân Giải","cn":"","loai":"cong-phap","loaiLabel":"Truyền thừa Cốt Văn","phamCap":"Vô thượng","hePhai":"Thạch Thôn","soHuu":["Thạch Hạo"],"blurb":"Tên bốn chữ do Liễu Thần đặt cho cục xương trắng khắc ký hiệu, ghi chép chân nghĩa vô thượng của Cốt Văn.","detail":"Là chân nghĩa vô thượng của Cốt Văn được khắc chi chít ký hiệu trên cục xương trắng óng như dương chi mỹ ngọc. Ký hiệu ẩn hiện tiếng ca ngâm của chư thiên thần ma, ảo diệu tới mức người thường nhìn lâu liền đủ để phun máu trọng thương. Cục xương rơi cùng Liễu Thần xuống Thạch Thôn mấy chục năm trước; sau im lặng hồi lâu, Liễu Thần lên tiếng đặt tên đúng bốn chữ Nguyên Thủy Chân Giải, rồi trao lại qua tộc trưởng cho nhóc tỳ, mở ra một truyền thừa cơ duyên lớn.","nguon":["@c0063"]},{"id":"bi-phap-khep-vet-thuong-bong-den","name":"Bí pháp khép vết thương cầm máu (bóng đen)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Bóng đen u linh","soHuu":["Bóng đen (u linh)"],"blurb":"Bí pháp dùng ký hiệu chư thiên khép miệng vết thương lồng ngực sau khi cấy Chí Tôn Cốt.","detail":"Sau khi ký hiệu chư thiên ngưng tụ thành Chí Tôn Cốt ẩn vào lồng ngực Thạch Nghị, bóng đen dùng ký hiệu tương tự khép miệng vết thương và cầm máu cho đứa bé.","nguon":["@c0057"]},{"id":"bao-thuat-kinh-thien-hoang-kim-chien-mau","name":"Bảo thuật kinh thiên (Hoàng Kim chiến mâu)","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Chưa rõ","hePhai":"Thạch Tộc","soHuu":["Thạch Tử Lăng"],"blurb":"Bảo thuật thi triển qua Hoàng Kim chiến mâu của Thạch Tử Lăng, uy thế như Chư Thiên thần linh cùng ngâm xướng chú ngôn.","detail":"Thạch Tử Lăng vung Hoàng Kim chiến mâu vạch một vòng, thi triển bảo thuật kinh thiên: âm thanh chú ngôn ầm ầm đinh tai nhức óc tựa như vô số Chư Thiên thần linh cùng ngâm xướng. Mấy lão già trong tộc ngăn cản trước mặt đều bị chấn động đánh bay, phun máu tươi, hoảng sợ. Bảo thuật này gắn với binh khí Hoàng Kim chiến mâu và uy thế cha con dòng Thạch Tử Lăng khi hắn quyết đại khai sát giới trả thù vụ con trai bị đoạt Chí Tôn cốt.","nguon":["@c0058"]},{"id":"nguyen-thuy-phu-van-truong-mau","name":"Nguyên thủy phù văn trên trường mâu","loai":"bao-thuat","loaiLabel":"Phù văn/Bảo Thuật","soHuu":["Thạch Tử Lăng"],"blurb":"Khi trường mâu của Thạch Tử Lăng vẩy lên, nguyên thủy phù văn liên miên hiện ra, tỏa ánh sáng hoàng kim quét về phía trước.","detail":"Nguyên thủy phù văn tự hiện trên chiến mâu hoàng kim của Thạch Tử Lăng khi vung, tạo ánh sáng hoàng kim rực rỡ đánh nổ Bảo Cụ đối thủ và làm mặt đất nứt khe lớn theo mỗi bước.","nguon":["@c0059"]},{"id":"trung-dong","name":"Trùng Đồng","aliases":["Trọng Đồng"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bẩm sinh — đặc chất Thánh Nhân Thần Nhân Thượng Cổ","hePhai":"Thạch tộc","soHuu":["Thạch Nghị"],"blurb":"Đặc chất bẩm sinh của Thánh Nhân Thần Nhân Thượng Cổ, mắt phát hào quang tự chữa lành và quấy nhiễu mọi Bảo Thuật.","detail":"Trùng đồng là đặc chất bẩm sinh hiếm có, mắt phát hào quang tạo kén bao thân tự chữa lành xương gãy và khép vết thương; có thể gia trì cho người khác nhìn thấu hư không và khe hở đòn đánh; bắn ký hiệu in vào hư không ảnh hưởng và quấy nhiễu mọi Bảo Thuật trong thiên địa. Kết hợp Chí Tôn Cốt trên thân Thạch Nghị đã thể hiện uy lực nghịch thiên khi chưa cấy đủ hai tháng.","nguon":["@c0061"]},{"id":"nguyen-thuy-chan-giai","name":"Nguyên Thủy Chân Giải","cn":"原始真解","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Vô thượng (chân nghĩa Cốt Văn)","hePhai":"Cốt Văn","soHuu":["Thạch Hạo"],"blurb":"Tên bốn chữ do Liễu Thần đặt cho cục xương trắng khắc chi chít ký hiệu, ghi chép chân nghĩa vô thượng của Cốt Văn.","detail":"Cục xương trắng óng như dương chi mỹ ngọc to bằng bàn tay, khắc vô số ký hiệu ẩn hiện tiếng ca ngâm chư thiên thần ma. Nhìn lâu sẽ phun máu bị trọng thương. Rơi cùng Liễu Thần xuống Thạch Thôn trong biển sét mấy chục năm trước, được tộc trưởng Thạch Vân Phong cất giữ rồi trao cho Thạch Hạo. Liễu Thần im lặng hồi lâu rồi lên tiếng đặt tên: Nguyên Thủy Chân Giải.","nguon":["@c0063"]},{"id":"thap-van-cuc-canh","name":"Thập Vạn Cực Cảnh","aliases":["Cực Cảnh mười vạn cân"],"loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Cột mốc sức mạnh thân thể — giơ được đá mười vạn cân, mức chỉ Thái Cổ Hung Thú Thiên Giai non mới đạt.","detail":"Mốc đột phá trong hệ luyện thể, đặc trưng là giơ được tảng đá mười vạn cân bằng một tay. Được mô tả là tiêu chuẩn của Thái Cổ Hung Thú Thiên Giai non — cực hiếm ở người thường. Thạch Hạo đạt được khi sắp tròn bảy tuổi sau gần một năm khổ luyện dưới thác nước.","nguon":["@c0065"]},{"id":"cuc-canh-ren-than","name":"Cực cảnh (rèn thân)","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Tiêu chuẩn tu thân Thái Cổ","hePhai":"Thái Cổ","soHuu":["Thạch Hạo"],"blurb":"Mức phán đoán tiềm năng thần cầm/thiên giai hung thú non — nâng nổi mười vạn cân, thân tự sinh quang huy là dấu hiệu đạt.","detail":"Tiêu chuẩn rèn thân thời Thái Cổ dùng để đánh giá tiềm năng thần cầm/thiên giai hung thú non. Phàm thai bình thường không làm nổi; đạt cực cảnh thì thân tự phát quang huy, một tay có thể phát ra mười vạn tám ngàn cân thần lực, sánh với thú non mạnh nhất như Kim Sí Đại Bằng, Chân Hống.","nguon":["@c0066"]},{"id":"phu-van","name":"Phù Văn","cn":"","loai":"khac","loaiLabel":"Văn tự tu luyện / bản chất bổn nguyên","phamCap":"","hePhai":"Thạch Tộc","soHuu":["Thạch Hạo"],"blurb":"Bản chất văn tự tu luyện được diễn giải trong khối xương trắng và trùng tu trong cơ thể Thạch Hạo.","detail":"Phù Văn là văn tự bổn nguyên của tu luyện; Nguyên Thủy Chân Giải giải thích ý nghĩa thâm ảo của nó. Sau khi ngộ, Thạch Hạo hiểu ý nghĩa bổn nguyên sâu nhất của Phù Văn và gầy dựng lại nó trong cơ thể — mỗi giọt máu chứa một Phù Văn khi trùng tu Bàn Huyết Cảnh.","nguon":["@c0067"]},{"id":"chien-than-do-luc","name":"Chiến Thần Đồ Lục","cn":"","loai":"cong-phap","loaiLabel":"Đồ lục / Công pháp gốc","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Đồ lục Thạch Hạo lĩnh ngộ thân pháp Kim Bằng sau khi xem Nguyên Thủy Chân Giải.","detail":"Chứa hình Kim Sí Đại Bằng quyết đấu thần linh cùng ảo diệu quỹ tích và vận chuyển ký hiệu. Từ đồ lục này Thạch Hạo lĩnh ngộ ra thân pháp Kim Bằng cực nhanh, hai tay lấp lóe ký hiệu vàng, dùng để vây bắt Độc Giác Thú.","nguon":["@c0068"]},{"id":"than-phap-kim-bang","name":"Thân pháp Kim Bằng","cn":"","aliases":["Kim Sí Đại Bằng"],"loai":"than-thong","loaiLabel":"Thân pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thân pháp cực nhanh Thạch Hạo lĩnh ngộ từ Chiến Thần Đồ Lục.","detail":"Khi thi triển, hai tay lấp lóe ký hiệu vàng, xé gió như một con Kim Bằng nhỏ, lướt ngang trời và đổi hướng như Thái Cổ Thần Cầm, tốc độ cực nhanh. Thạch Hạo dùng thân pháp này lao vào bầy Độc Giác Thú né đòn ánh sáng bạc và bắt sống một con.","nguon":["@c0068"]},{"id":"phap-mon-hoa-than-lo","name":"Pháp môn hóa Thần Lô cất giấu thần tinh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ngộ từ ký hiệu Thôn Thiên Tước trong Nguyên Thủy Chân Giải","soHuu":["Thạch Hạo"],"blurb":"Kỹ pháp Thạch Hạo ngộ được để hóa ký hiệu thành Thần Lô nhỏ, ẩn giấu tinh khí vào cơ thể thay vì đột phá.","detail":"Dù không có pháp môn vận chuyển ký hiệu của Thôn Thiên Tước, Thạch Hạo vẫn ngộ ra được một ít đạo lý ẩn giấu tinh khí vào trong cơ thể; khi hút thần tinh trong trứng ngũ sắc suýt đột phá, nó hóa từng ký hiệu thành một Thần Lô nhỏ để cất giấu tinh khí, giữ cho cảnh giới cơ sở càng thêm vững chắc theo lời dặn của Liễu Thần.","nguon":["@c0070"]},{"id":"bao-thuat-thai-co-than-vuong","name":"Bảo thuật Thái Cổ Thần Vương","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thái Cổ","soHuu":[],"blurb":"Bí thuật của Thái Cổ Thần Vương; nếu ấp nở và nuôi lớn trứng do hậu duệ Thái cổ thần điểu sinh có thể dò xét một phần bí mật của bảo thuật này.","detail":"Được nhóm bà lão nhắc tới khi bàn giá trị quả trứng bị Thạch Hạo và tiểu thú ăn mất — trứng vốn là chìa khóa dò xét bảo thuật, nay đã hỏng.","nguon":["@c0072"]},{"id":"nhan-hoang-phu-van","name":"Nhân Hoàng phù văn","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thông thiên","hePhai":"Thạch quốc","soHuu":["Nhân Hoàng"],"blurb":"Phù văn thông thiên của Nhân Hoàng Thạch quốc, thần uy cái thế giúp quốc thế hưng thịnh mấy trăm năm, không thế lực nào dám phản.","detail":"Được nhắc như cột trụ khiến Thạch quốc cực thịnh; là gốc rễ uy danh Nhân Hoàng và là lý do biên thùy Thạch quốc yên ổn.","nguon":["@c0072"]},{"id":"phu-van-ngung-luyen-vu-khi","name":"Phù văn ngưng luyện vũ khí trong thân thể","loai":"bi-thuat","loaiLabel":"Bí thuật phù văn","hePhai":"Phù văn","soHuu":["Liễu Thần"],"blurb":"Thủ đoạn phù văn dựng/thai nghén vũ khí ngay trong thân thể để tấn công xuyên thủng mọi thứ.","detail":"Cây Tế linh ở thành Trùng Vân dùng phù văn thai nghén ba phi kiếm đỏ/trắng/tím từ ba đóa hoa trên thân, phóng ra chém đứt đầu thủ lĩnh hung cầm. Thạch Hạo quan sát trận đánh, nhận ra phù văn còn có thể dùng để dựng vũ khí ngay trong thân thể tấn công xuyên thủng mọi thứ và cân nhắc bắt chước.","nguon":["@c0073"]},{"id":"hoa-quang-thuat","name":"Hỏa Quang Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Hung khấu","soHuu":["Thủ lĩnh hung khấu"],"blurb":"Bí thuật phù văn công kích của thủ lĩnh hung khấu, xuất ra vầng lửa rực dùng để đốt cháy làng xóm.","detail":"Một thủ lĩnh hung khấu vận phù văn xuất ra một vầng lửa rực chiếu khắp đầu thôn, vốn định thiêu rụi Thạch thôn. Đòn này bị Thạch Hạo đẩy một chưởng dập tắt và đánh bay tên thủ lĩnh cuối cùng xa mấy chục thước.","nguon":["@c0081"]},{"id":"phu-van-xoay-hut","name":"Phù văn xoáy hút","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật phù văn","phamCap":"","hePhai":"","soHuu":["Tiểu Thạch Hạo"],"blurb":"Thủ pháp phù văn tạo vòng xoáy hút và cắn nát vũ khí đối phương.","detail":"Bí thuật phù văn của Thạch Hạo: tay trái vẽ vòng tròn tạo ra một vòng xoáy phù văn, hút lấy tên sắt và cắn nát chúng ngay giữa không trung. Thuộc dạng phù văn công-thủ tiện dụng trong cận chiến, khi Thạch Hạo một mình xông vào sơn trại bọn cướp.","nguon":["@c0082"]},{"id":"bien-than-xuyen-son-giap-hinh-nguoi","name":"Biến thân Xuyên Sơn Giáp hình người","cn":"","loai":"than-thong","loaiLabel":"Thần thông biến hóa","phamCap":"","hePhai":"","soHuu":["Đại thủ lĩnh bọn cướp"],"blurb":"Thần thông biến hóa cầu Tế Linh ban sức mạnh, hóa thành Xuyên Sơn Giáp dạng người.","detail":"Đại thủ lĩnh bọn cướp cầu Tế Linh ban sức mạnh, cả người biến thành Xuyên Sơn Giáp hình người, toàn thân bùng hào quang, phòng ngự phù văn dày đặc gần như vô tận. Ở dạng này hắn có sức chiến đấu vượt trội, đối đầu ngang ngửa Bảo Thuật trăng bạc của Thạch Hạo trong hơn mười chiêu trước khi bị Thái Cổ Ma Cầm phá vỡ.","nguon":["@c0082"]},{"id":"than-nguyet","name":"Thần Nguyệt","aliases":["Hai vầng trăng bạc","Vòng xoáy bạc","Cối xay bạc"],"loai":"than-thong","loaiLabel":"Thần thông / Bảo Thuật","phamCap":"Chưa rõ","hePhai":"Bảo Thuật của nhóc tỳ","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật hai vầng trăng bạc: nhóc tỳ hô lên, hai tay phát sáng tạo hai vầng trăng bạc chạm nhau hóa thành vòng xoáy bạc có lực hút mài mòn.","detail":"Nhóc tỳ hô “Mở ra!”, hai tay phát sáng tạo hai vầng trăng bạc; hai vầng trăng chạm chung một chỗ hóa thành vòng xoáy bạc có lực hút mài mòn, dùng để tạm áp chế cơn mưa vảy vàng kim Bảo Cụ của Tế Linh Xuyên Sơn Giáp.","nguon":["@c0083"]},{"id":"chop-giat-loi-dien","name":"Chớp Giật (Lôi điện)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông bẩm sinh Thái Cổ","hePhai":"Thần thông bẩm sinh của Toan Nghê","soHuu":["Thạch Hạo"],"blurb":"Thần thông bẩm sinh của Toan Nghê: mười ngón tay phóng tia chớp vàng hủy diệt, uy như Lôi Thần hạ phàm.","detail":"Là thần thông bẩm sinh của di chủng Thái Cổ Toan Nghê mà Thạch Hạo cảm ngộ được. Khi thi triển, mười ngón tay đồng loạt phóng ra tia chớp vàng cộng hưởng với quang vụ, uy thế kinh người tựa Lôi Thần giáng thế. Trong trận chém Tế Linh, đây là đòn chủ lực: nhân lúc Xuyên Sơn Giáp dồn hết vảy vàng đi công kích để thân trần mất bảo vệ, tia chớp đánh vào đầu và thân khiến địch cháy khét, gãy xương, trọng thương nặng nề.","nguon":["@c0084"]},{"id":"suong-mu-toan-nghe","name":"Sương Mù (thần thông Toan Nghê)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông bẩm sinh Thái Cổ","hePhai":"Thần thông bẩm sinh của Toan Nghê","soHuu":["Thạch Hạo"],"blurb":"Thần thông giăng sương mù phủ kín vùng núi để ẩn núp và di chuyển đổi vị trí giữa trận.","detail":"Một thần thông bẩm sinh khác của Toan Nghê. Thạch Hạo triển sương mù dày phủ kín cả vùng núi, ẩn thân di chuyển liên tục để đổi vị trí, khiến Tế Linh dù sức mạnh đáng sợ vẫn không tìm ra nó. Trong màn sương, Thạch Hạo phối hợp sấm chớp và mưu kế ném mồi để dụ địch lộ sơ hở trước khi ra đòn kết liễu.","nguon":["@c0084"]},{"id":"dong-thien-canh","name":"Động Thiên (Miệng núi lửa)","cn":"","aliases":["Miệng núi lửa","Dung nham thông đạo","Bất hủ thông đạo"],"loai":"than-thong","loaiLabel":"Thần thông cảnh giới","phamCap":"Cảnh giới tu hành cao","hePhai":"Tộc nhân Đại Hoang","soHuu":["Thạch Hạo"],"blurb":"Cảnh giới mở bên trong hoặc ngoài thân một thông đạo bất hủ, câu thông hư không để cướp đoạt thiên địa tạo hóa.","detail":"Mỗi Động Thiên mở ra tăng một cơ số tiềm năng cho phù văn thần lực. Theo lời lão tộc trưởng, sáu động thiên là tài ba, bảy là thiên tài, tám là dị bẩm hiếm như phượng mao lân giác, chín thì chỉ nghe trong sách cổ. Liễu Thần về sau khẳng định tám động thiên chỉ là tiêu chuẩn nhân tộc, chín động thiên có thực, còn mười động thiên mới là cực hạn — tôn sư chân chính. Nhóc tỳ tám tuổi rưỡi đã mở tới bốn động thiên.","nguon":["@c0086"]},{"id":"thong-thien-lu-trinh","name":"Thông Thiên Lữ Trình","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thủ đoạn của Liễu Thần","soHuu":["Liễu Thần"],"blurb":"Thủ đoạn mở giới của Cây Liễu, dẫn người vào Hư Thần Giới.","detail":"Năm cành liễu bay vút lên hóa thành xích thần trật tự, xông lên trời làm mây xanh rực cháy rồi xuyên thủng bầu trời như mở ra một cánh cửa pháp tắc, đưa ý chí tinh thần của người tu vào Hư Thần Giới. Đây là cách riêng của Liễu Thần, khác con đường chính thống là ‘cả nước cùng tế thiên’ của các quốc gia cổ.","nguon":["@c0087"]},{"id":"ca-nuoc-cung-te-thien","name":"Cả Nước Cùng Tế Thiên","cn":"","loai":"bi-thuat","loaiLabel":"Nghi thức","phamCap":"Không rõ","hePhai":"Quốc gia cổ tín ngưỡng Thần Linh","soHuu":[],"blurb":"Nghi thức chính thống để cường giả cảm ngộ và ra vào Hư Thần Giới.","detail":"Các quốc gia cổ giữ tín ngưỡng Thần Linh cổ đã chết tổ chức cả nước trang trọng cúng tế trời để kế thừa đồ vật Thần Linh lưu lại; cường giả tu tới trình độ nhất định nhờ đó cảm ngộ và có tư cách ra vào Hư Thần Giới. Thạch thôn ở Đại Hoang xa xôi không tế thiên nên không thể tự vào.","nguon":["@c0087"]},{"id":"thong-dao-phu-van","name":"Thông Đạo Phù Văn","cn":"","loai":"khac","loaiLabel":"Cơ chế dịch chuyển","phamCap":"Không rõ","hePhai":"Hư Thần Giới","soHuu":[],"blurb":"Thông đạo màu vàng trên tảng đá khảm Bảo Cốt, dịch chuyển người tới khu vực khác.","detail":"Thông đạo màu vàng lóe Phù Văn trên các tảng đá khảm Nguyên Thủy Bảo Cốt; dùng để đưa người từ Sơ Thủy Địa lên khu vực cấp cao hơn sau khi tu hành viên mãn. Nhóc tỳ vì đào Bảo Cốt mà vô tình phá hỏng một thông đạo về ngoại giới.","nguon":["@c0087"]},{"id":"ngu-hoa-cuc-canh-hoa-van-tien","name":"Ngự hỏa Cực Cảnh (tay nghề Hỏa Vân Tiên)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực Cảnh (kỷ lục Sơ Thủy Địa)","hePhai":"Hư Thần Giới — Sơ Thủy Địa","soHuu":["Hỏa Vân Tiên"],"blurb":"Tay nghề ngự hỏa đạt Cực Cảnh: giẫm trên lửa trời mà đi.","detail":"Kỹ nghệ khống chế lửa của Hỏa Vân Tiên, đạt tới Cực Cảnh ở Sơ Thủy Địa; người tu có thể giẫm trên lửa trời mà đi — được ghi trên bia đá kỷ lục Sơ Thủy Địa từ mấy vạn năm trước.","nguon":["@c0089"]},{"id":"nhat-niem-hoa-khai-yeu-nguyet","name":"Nhất Niệm Hoa Khai (thần thông Yêu Nguyệt)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Vô địch Bàn Huyết Cảnh (kỷ lục Sơ Thủy Địa)","hePhai":"Hư Thần Giới — Sơ Thủy Địa","soHuu":["Yêu Nguyệt"],"blurb":"Một niệm hoa nở, gỗ khô tái sinh; sinh mệnh lực vô địch Bàn Huyết Cảnh.","detail":"Thần thông của Yêu Nguyệt: một niệm hoa nở, gỗ khô tái sinh, sinh mệnh lực mạnh mẽ không ai vượt qua ở Bàn Huyết Cảnh — được ghi trên bia đá kỷ lục Sơ Thủy Địa từ ngàn năm trước.","nguon":["@c0089"]},{"id":"xich-phu-van-quan-bo-cuop","name":"Xích phù văn quấn địch","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Phù văn","soHuu":["Thạch Hạo"],"blurb":"Nhóc tỳ dùng sợi xích phù văn quấn bọn cướp thành một chùm làm lá chắn thịt chống Bảo Cụ Xích Vũ.","detail":"Thủ đoạn phù văn của nhóc tỳ ở Sơ Thủy Địa: dùng xích phù văn quấn bọn người muốn cướp bảo cốt thành một chùm, giăng phù văn đầy giữa hai tay để chống đỡ Bảo Cụ; bốn năm tên bị Xích Vũ đâm xuyên hóa thành tro trong lúc làm lá chắn.","nguon":["@c0090"]},{"id":"co-tran-bon-khoi-bao-cot","name":"Cổ trận bốn khối bảo cốt","loai":"bi-thuat","loaiLabel":"Trận pháp","hePhai":"Tứ đại gia tộc","soHuu":["Tứ đại gia tộc"],"blurb":"Trận pháp tứ đại gia tộc dùng bốn khối bảo cốt cố định hư không, phù văn đan xen tạo tấm chắn xanh giam đối thủ.","detail":"Bốn khối Phù Cốt kỳ dị bố khắp bốn phương, phù văn đan xen hóa hào quang lam giam địch. Lần đầu tung ra chỉ là hư ảnh Bảo Cụ hiện hóa (dùng một lần) vì tứ đại gia tộc đã mất Xích Vũ nên dè dặt; lần sau bố lại thuần dùng để tiêu diệt, va chạm với Bảo Phiến đỏ tạo sóng thần lực ngập trời.","nguon":["@c0092"]},{"id":"thien-thu-ky-hieu","name":"Thiên Thư ký hiệu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hạ U Vũ"],"blurb":"Thần thông hộ thân in ký hiệu như Thiên Thư phủ khắp thân, khiến cơ thể trơn như cá.","detail":"Ký hiệu như Thiên Thư in trong hư không phủ khắp toàn thân Hạ U Vũ, khiến cơ thể trơn tuột, dù bị đối phương tóm được vẫn trượt khỏi tay thoát ra ngoài. Nàng dùng nó để thoát khỏi thế khống chế của nhóc tỳ Thạch Hạo.","nguon":["@c0071"]},{"id":"than-van-phong-ngu-bao-cot","name":"Thần Văn (cốt văn phòng ngự)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":[],"blurb":"Cốt văn phòng ngự tự bạo phát trên các khối Bảo Cốt khi bị công kích.","detail":"Khi các khối Bảo Cốt gắn trên tảng đá thông đạo bị Phù Văn công kích, chúng tự bạo phát Thần Văn để phòng ngự. Người ta phát hiện dùng sức mạnh Phù Văn càng nhiều thì Thần Văn phòng ngự của Bảo Cốt càng mạnh, nên muốn phá vỡ phải hạn chế Phù Văn và dùng sức mạnh thân thể.","nguon":["@c0088"]},{"id":"than-du-thai-hu","name":"Thần du Thái Hư","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thuật thần du cho tinh thần rời thân xác đến Hư Thần Giới.","detail":"Thạch Hạo dùng thuật này để tinh thần rời thân đến Hư Thần Giới trong khi thân xác bất động ở Thạch thôn dưới sự trông nom của Liễu thần. Thanh Phong cũng có thể ngồi xếp bằng cảm ứng vào Hư Thần Giới bằng phương pháp tương tự.","nguon":["@c0095"]},{"id":"phu-van-tran-vuc","name":"Phù Văn trận vực","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Bổ Thiên các","soHuu":["Bổ Thiên các"],"blurb":"Trận phù văn dày đặc do Bổ Thiên các bố trí tại Nguyên Thủy chiến trường để sàng lọc đệ tử vượt ải.","detail":"Trận vực chia làm tám khu bao phủ Nguyên Thủy chiến trường; thí sinh xông qua khu Phù Văn trận vực được xem là đậu, ai xuyên thủng trận vực có thể lên chiến trường tầng hai. Cửa ải cuối cùng đặc biệt khó, chuẩn bị cho thiên tài, có nguy cơ khiến cả khu vực toàn quân bị diệt. Thạch Hạo dùng bạo lực nện sụp Phù Văn thay vì giải trận từng bước.","nguon":["@c0098"]},{"id":"muoi-tia-chop-vang","name":"Mười tia chớp vàng","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Thạch Hạo","soHuu":["Thạch Hạo"],"blurb":"Thần thông ngón tay: xòe mười ngón bắn ra mười tia chớp thô to màu vàng óng.","detail":"Nhóc tỳ xòe mười ngón tay, bắn ra mười tia chớp thô to màu vàng óng nổ tung trên thân Cổ Ngạc, làm nó cháy đen và bong vảy giáp.","nguon":["@c0100"]},{"id":"bay-muoi-hai-bien-hoa","name":"Bảy mươi hai biến hóa","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo Thuật uy chấn Thái Cổ","soHuu":["Chu Yếm"],"blurb":"Môn Bảo Thuật biến hóa chi đạo có một không hai từng uy chấn Thái Cổ, tương truyền Chu Yếm hiểu được.","detail":"Môn Bảo Thuật biến hóa chi đạo mà Chu Yếm tương truyền hiểu được, từng uy chấn Thái Cổ. Hiện tại Bóng Lông (Chu Yếm) chỉ còn tiểu biến hóa do phù văn bị phá nát, chưa tái hiện được toàn bộ bảy mươi hai biến hóa.","nguon":["@c0097"]},{"id":"tieu-bien-hoa","name":"Tiểu biến hóa","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tiểu thần thông (biến hóa chi đạo)","soHuu":["Thạch Hạo","Chu Yếm"],"blurb":"Tiểu thần thông biến hóa chi đạo, đổi hình dáng tướng mạo xương cốt; Thạch Hạo học từ Bóng Lông.","detail":"Tiểu thần thông thuộc biến hóa chi đạo, cho phép đổi hình dáng tướng mạo và xương cốt. Thạch Hạo học từ Bóng Lông và dùng để biến mặt tròn múp míp như trái táo nguỵ trang.","nguon":["@c0097"]},{"id":"ba-dau-sau-tay","name":"Ba đầu sáu tay","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông cái thế","soHuu":["Chu Yếm"],"blurb":"Một trong hai đại thần thông cái thế của Chu Yếm, nay không tái hiện được do phù văn bị phá.","detail":"Đại thần thông cái thế của Chu Yếm, cùng với bảy mươi hai biến hóa. Hiện chưa tái hiện được do phù văn Bóng Lông bị phá nát.","nguon":["@c0097"]}]};